@import "tailwindcss";
@import "tw-animate-css";

@plugin "@tailwindcss/typography";

/* Include sources for class scanning across monorepo */
@source "../**/*.{ts,tsx}";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-input-bg: var(--input-bg);
  --color-ring: var(--ring);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
  --animate-accordion-down: accordion-down 0.2s ease-out;
  --animate-accordion-up: accordion-up 0.2s ease-out;
}

@keyframes accordion-down {
  from {
    height: 0;
  }
  to {
    height: var(--radix-accordion-content-height);
  }
}

@keyframes accordion-up {
  from {
    height: var(--radix-accordion-content-height);
  }
  to {
    height: 0;
  }
}

@theme inline {
  /* Text size overrides - shifted up by one level (smaller) */
  --text-xs: 0.625rem; /* was 0.75rem, now smaller */
  --text-xs--line-height: 1rem;
  --text-sm: 0.75rem; /* was 0.875rem, now xs */
  --text-sm--line-height: 1rem;
  --text-base: 0.875rem; /* was 1rem, now sm */
  --text-base--line-height: 1.25rem;
  --text-md: 0.9375rem; /* 15px - bridge between base and lg */
  --text-md--line-height: 1.375rem;
  --text-lg: 1rem; /* was 1.125rem, now base */
  --text-lg--line-height: 1.5rem;
  --text-xl: 1.125rem; /* was 1.25rem, now lg */
  --text-xl--line-height: 1.75rem;
  --text-2xl: 1.25rem; /* was 1.5rem, now xl */
  --text-2xl--line-height: 1.75rem;
  --text-3xl: 1.5rem; /* was 1.875rem, now 2xl */
  --text-3xl--line-height: 2rem;
  --text-4xl: 1.875rem; /* was 2.25rem, now 3xl */
  --text-4xl--line-height: 2.25rem;
  --text-5xl: 2.25rem; /* was 3rem, now 4xl */
  --text-5xl--line-height: 2.5rem;
  --text-6xl: 3rem; /* was 3.75rem, now 5xl */
  --text-6xl--line-height: 1;
  --text-7xl: 3.75rem; /* was 4.5rem, now 6xl */
  --text-7xl--line-height: 1;
  --text-8xl: 4.5rem; /* was 6rem, now 7xl */
  --text-8xl--line-height: 1;
}

:root {
  --radius: 0.25rem;
  --background: oklch(1 0 0);
  --foreground: oklch(0.145 0 0);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.145 0 0);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.145 0 0);
  --primary: oklch(0.205 0 0);
  --primary-foreground: oklch(0.985 0 0);
  --secondary: oklch(0.97 0 0);
  --secondary-foreground: oklch(0.205 0 0);
  --muted: oklch(0.97 0 0);
  --muted-foreground: oklch(0.556 0 0);
  --accent: oklch(0.97 0 0);
  --accent-foreground: oklch(0.205 0 0);
  --destructive: oklch(0.577 0.245 27.325);
  --destructive-foreground: oklch(1 0 0);
  --border: oklch(0.922 0 0);
  --input: oklch(0.922 0 0);
  --input-bg: oklch(1 0 0); /* Same as background by default */
  --ring: oklch(0.708 0 0);
  --sidebar: oklch(1 0 0);
  --sidebar-foreground: oklch(0.145 0 0);
  --sidebar-accent: oklch(0.97 0 0);
  --sidebar-accent-foreground: oklch(0.205 0 0);
  --sidebar-border: oklch(0.922 0 0);
  --sidebar-ring: oklch(0.708 0 0);

  /* Brand colors */
  --brand-orange: oklch(0.5913 0.2286 31.28);
  /* Pitch deck red colors */
  --pitch-deck-red: oklch(0.5023 0.2159 28.72);
  --pitch-deck-red-overlay: oklch(0.5738 0.2382 30.35);

  /* Unified scrollbar variables */
  --scrollbar-size: 8px;
  --scrollbar-size-thin: 6px;
  --scrollbar-track-bg: transparent;
  --scrollbar-thumb-bg: oklch(0 0 0 / 0.2);
  --scrollbar-thumb-bg-hover: oklch(0 0 0 / 0.3);
  --scrollbar-thumb-radius: 4px;
}

.dark {
  --background: oklch(0.2178 0 0);
  --foreground: oklch(0.8853 0 0);
  --card: oklch(0.2435 0 0);
  --card-foreground: oklch(0.8853 0 0);
  --popover: oklch(0.2178 0 0); /* Match background for consistency */
  --popover-foreground: oklch(0.8853 0 0);
  --primary: oklch(1 0 0);
  --primary-foreground: oklch(0.2178 0 0);
  --secondary: oklch(0.3092 0 0);
  --secondary-foreground: oklch(0.8853 0 0);
  --muted: oklch(0.285 0 0);
  --muted-foreground: oklch(0.5999 0 0);
  --accent: oklch(0.26 0 0); /* Consistent accent color matching sidebar */
  --accent-foreground: oklch(0.8853 0 0);
  --destructive: oklch(0.6591 0.153 22.1703);
  --destructive-foreground: oklch(1 0 0);
  --border: oklch(0.329 0 0);
  --input: oklch(0.3092 0 0);
  --input-bg: oklch(
    0.24 0 0
  ); /* Very subtle, slightly lighter than background */
  --ring: oklch(0.7058 0 0);
  --sidebar: oklch(0.155 0 0); /* Darker than background for contrast */
  --sidebar-foreground: oklch(0.8853 0 0);
  --sidebar-accent: oklch(0.22 0 0);
  --sidebar-accent-foreground: oklch(0.8853 0 0);
  --sidebar-border: oklch(0.26 0 0);
  --sidebar-ring: oklch(0.7058 0 0);
  --scrollbar-thumb-bg: oklch(1 0 0 / 0.2);
  --scrollbar-thumb-bg-hover: oklch(1 0 0 / 0.3);
}

/* Typography plugin */
@utility prose {
  --tw-prose-body: var(--color-foreground);
  --tw-prose-headings: var(--color-foreground);
  --tw-prose-lead: var(--color-muted-foreground);
  --tw-prose-links: var(--color-primary);
  --tw-prose-bold: var(--color-foreground);
  --tw-prose-counters: var(--color-foreground);
  --tw-prose-bullets: var(--color-muted-foreground);
  --tw-prose-hr: var(--color-muted-foreground);
  --tw-prose-quotes: var(--color-muted-foreground);
  --tw-prose-quote-borders: var(--color-border);
  --tw-prose-captions: var(--color-muted-foreground);
  --tw-prose-code: var(--color-foreground);
  --tw-prose-pre-code: var(--color-foreground);
  --tw-prose-pre-bg: var(--color-background);
  --tw-prose-th-borders: var(--color-border);
  --tw-prose-td-borders: var(--color-border);
  --tw-prose-invert-body: var(--color-foreground);
  --tw-prose-invert-headings: var(--color-foreground);
  --tw-prose-invert-lead: var(--color-muted-foreground);
  --tw-prose-invert-links: var(--color-primary);
  --tw-prose-invert-bold: var(--color-foreground);
  --tw-prose-invert-counters: var(--color-foreground);
  --tw-prose-invert-bullets: var(--color-foreground);
  --tw-prose-invert-hr: var(--color-muted-foreground);
  --tw-prose-invert-quotes: var(--color-muted-foreground);
  --tw-prose-invert-quote-borders: var(--color-border);
  --tw-prose-invert-captions: var(--color-muted-foreground);
  --tw-prose-invert-code: var(--color-foreground);
  --tw-prose-invert-pre-code: var(--color-foreground);
  --tw-prose-invert-pre-bg: var(--color-background);
  --tw-prose-invert-th-borders: var(--color-border);
  --tw-prose-invert-td-borders: var(--color-border);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    font-family:
      var(--font-geist-sans), var(--font-sans), ui-sans-serif, system-ui,
      sans-serif;
    @apply bg-background text-foreground;
  }
  .font-sans {
    font-family:
      var(--font-geist-sans), var(--font-sans), ui-sans-serif, system-ui,
      sans-serif;
  }
  code,
  pre,
  kbd,
  samp,
  .font-mono {
    letter-spacing: normal;
  }
}

@layer utilities {
  .chat-container {
    @apply max-w-3xl mx-auto;
  }

  /* Unified page gutters for horizontal padding */
  .page-gutter {
    @apply px-8 md:px-16; /* 2rem → 3rem at md */
  }

  /* Scrollbar utilities - apply to both vertical and horizontal */
  .scrollbar-default {
    scrollbar-color: var(--scrollbar-thumb-bg) var(--scrollbar-track-bg);
    scrollbar-width: thin;
  }
  .scrollbar-default::-webkit-scrollbar {
    width: var(--scrollbar-size);
    height: var(--scrollbar-size);
  }
  .scrollbar-default::-webkit-scrollbar-thumb {
    background: var(--scrollbar-thumb-bg);
    border-radius: var(--scrollbar-thumb-radius);
  }
  .scrollbar-default::-webkit-scrollbar-thumb:hover {
    background: var(--scrollbar-thumb-bg-hover);
  }

  .scrollbar-thin {
    scrollbar-color: var(--scrollbar-thumb-bg) var(--scrollbar-track-bg);
    scrollbar-width: thin;
  }
  .scrollbar-thin::-webkit-scrollbar {
    width: var(--scrollbar-size-thin);
    height: var(--scrollbar-size-thin);
  }
  .scrollbar-thin::-webkit-scrollbar-thumb {
    background: var(--scrollbar-thumb-bg);
    border-radius: calc(var(--scrollbar-thumb-radius) - 1px);
  }
  .scrollbar-thin::-webkit-scrollbar-thumb:hover {
    background: var(--scrollbar-thumb-bg-hover);
  }
}

